import{_ as t,o as r,c as e,ai as n,aj as o,ak as s}from"./chunks/framework.C3VoC05s.js";const b=JSON.parse('{"title":"NJUPT Suan 插件介绍","description":"","frontmatter":{},"headers":[],"relativePath":"astrbot-plugin/introduction.md","filePath":"astrbot-plugin/introduction.md"}'),i={name:"astrbot-plugin/introduction.md"};function p(l,a,c,d,h,_){return r(),e("div",null,[...a[0]||(a[0]=[n('<h1 id="njupt-suan-插件介绍" tabindex="-1">NJUPT Suan 插件介绍 <a class="header-anchor" href="#njupt-suan-插件介绍" aria-label="Permalink to “NJUPT Suan 插件介绍”">​</a></h1><p><strong>NJUPT Suan</strong> - <strong>芒果酸</strong></p><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to “这是什么”">​</a></h2><p>这是一个 Astrbot 插件。</p><p><a href="https://astrbot.app/" target="_blank" rel="noreferrer">Astrbot</a> 是一个跨平台 AI 助手，让 AI 直接工作在聊天软件中。你也可以把它当成一个聊天机器人，或者一个不能聊天只负责执行任务的工具人。</p><p>NJUPT Suan 当中的 <code>Suan</code> 是芒果酸酸的酸，本插件为 Astrbot 中运行的 LLM 提供了与 NJUPT 有关的工具。</p><h2 id="功能介绍" tabindex="-1">功能介绍 <a class="header-anchor" href="#功能介绍" aria-label="Permalink to “功能介绍”">​</a></h2><h3 id="生成课程表" tabindex="-1">生成课程表 <a class="header-anchor" href="#生成课程表" aria-label="Permalink to “生成课程表”">​</a></h3><div class="info custom-block"><p class="custom-block-title">已归档</p><p>不再支持生成以下图片。</p></div><p><img src="'+o+'" alt="单日课表"></p><p><img src="'+s+'" alt="单周课表"></p><p>上方预览效果是在插件设置中启用了忽略空行空列之后的效果。如果显示完全的话，那么完全没有课的行（时间段）和列（天）都会显示完整。</p><p>图片的标题由 LLM 决定，因此你可以通过提示词来让 LLM 生成更适合的标题。</p><p>此功能被包装为 LLM 工具，供 LLM 主动调用，需要在 Astrbot 中使用支持工具调用的模型。</p><h2 id="技术路线" tabindex="-1">技术路线 <a class="header-anchor" href="#技术路线" aria-label="Permalink to “技术路线”">​</a></h2><p>Astrbot 是使用 Python 构建的，其插件也使用 Python，因此 NJUPT Suan 也使用 Python 构建。</p>',16)])])}const m=t(i,[["render",p]]);export{b as __pageData,m as default};
